SELECT driver_gene_id 
FROM driver_genes 
WHERE cancer_type_id = (SELECT cancer_type_id FROM cancer_types WHERE cancer_type_name = 'PANCAN');

SELECT DISTINCT u.username
FROM users u
JOIN rescue_notes rn ON u.username = rn.added_by;

SELECT cancer_type_name, incidence_rate
FROM cancer_types
ORDER BY incidence_rate DESC;

SELECT cancer_type_name 
FROM cancer_types 
WHERE cancer_type_id = 1;
